1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Policy {
8	  items: Item[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25, moonstone: 25 };
16	const DEFAULT_BASE_PREMIUM = 60;
17	
18	const CURSE_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
21	const BLOCK_SIZE = 3;
22	const BLOCK_PREMIUM = 60;
23	
24	function basePremiumForType(type: string): number {
25	  return BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM;
26	}
27	
28	function itemSurcharges(item: Item): number {
29	  const base = basePremiumForType(item.type);
30	  let surcharge = 0;
31	  if (item.cursed) {
32	    surcharge += base * CURSE_SURCHARGE_RATE;
33	  }
34	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
35	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
36	  }
37	  return surcharge;
38	}
39	
40	function countByType(items: Item[]): Record<string, number> {
41	  const counts: Record<string, number> = {};
42	  for (const item of items) {
43	    counts[item.type] = (counts[item.type] ?? 0) + 1;
44	  }
45	  return counts;
46	}
47	
48	function itemGroupPremium(type: string, count: number): number {
49	  if (count === BLOCK_SIZE) {
50	    return BLOCK_PREMIUM;
51	  }
52	  return count * basePremiumForType(type);
53	}
54	
55	export function quote(policy: Policy) {
56	  const counts = countByType(policy.items);
57	
58	  let basePremium = 0;
59	  for (const [type, count] of Object.entries(counts)) {
60	    basePremium += itemGroupPremium(type, count);
61	  }
62	
63	  let totalItemSurcharges = 0;
64	  for (const item of policy.items) {
65	    totalItemSurcharges += itemSurcharges(item);
66	  }
67	
68	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
69	  const premium = Math.ceil(basePremium + totalItemSurcharges + firstInsuranceSurcharge + PROCESSING_FEE);
70	  return { premium };
71	}
72	
73	export function claim() {
74	  return undefined;
75	}
